local dnadesign = require("dnadesign")
local fix = dnadesign.fix
local codon = dnadesign.codon

describe("fix", function()
    -- Load test sequences
    local sequences = {
        reversion_seq = "GGACGAGACGGC", -- from TestReversion
        phusion = "", -- from TestCds
        bla_with_repeat = "", -- from TestCds
        target_bla_without_repeat = "", -- from TestCds
        complex_gene = "", -- from TestBtgZIComplexFix
        buffer_failure = "", -- from TestBufferFailure
        too_much_repeat = "", -- from TestTooMuchRepeat
        bad_codon_bla = "", -- from TestBadCodonTable
        panic_index = "", -- from TestPanicIndex
        ndei_fix = "", -- from TestNdeIFix
    }

    it("should fix reversion cases", function()
        local ecoli_table = codon.default_tables["ecoli"]
        local functions = {
            fix.remove_sequence({"GGTCTC", "CGTCTC"}, "TypeIIS restriction enzyme site.")
        }
        local result, changes, err = fix.cds(sequences.reversion_seq, ecoli_table, functions)
        assert.is_nil(err)
    end)

    it("should handle basic CDS operations", function()
        local ecoli_table = codon.default_tables["ecoli"]
        local functions = {
            fix.remove_sequence({
                "GAAGAC", "GGTCTC", "GCGATG", "CGTCTC", 
                "GCTCTTC", "CACCTGC"
            }, "TypeIIS restriction enzyme site.")
        }
        
        -- Test simple TAT fix
        local fixed_seq, _, _ = fix.cds_simple("ATGTATTGA", ecoli_table, {"TAT"})
        assert.equals("ATGTACTGA", fixed_seq)

        -- Test GC content fixes
        local gc_functions = {fix.gc_content_fixer(0.90, 0.10)}
        local fixed_gc, _, _ = fix.cds("GGGCCC", ecoli_table, gc_functions)
        assert.equals("GGTCCC", fixed_gc)
        
        local fixed_at, _, _ = fix.cds("AAATTT", ecoli_table, gc_functions)
        assert.equals("AAATTC", fixed_at)
    end)

    it("should handle bad inputs", function()
        local ecoli_table = codon.default_tables["ecoli"]
        local functions = {
            fix.remove_sequence({
                "GAAGAC", "GGTCTC", "GCGATG", "CGTCTC", 
                "GCTCTTC", "CACCTGC"
            }, "TypeIIS restriction enzyme site")
        }
        
        -- Test sequence not divisible by 3
        local _, _, err = fix.cds("AT", ecoli_table, functions)
        assert.is_not_nil(err)
        
        -- Test bad GC bias
        local bad_gc_functions = {
            fix.gc_content_fixer(0.10, 0.05)
        }
        local _, _, err2 = fix.cds("GGG", ecoli_table, bad_gc_functions)
        assert.is_not_nil(err2)
    end)

	it("should handle case where no changes are needed", function()
        local ecoli_table = codon.default_tables["ecoli"]
        local functions = {
            fix.remove_sequence({"AAAAAA"}, "Test sequence not present.")
        }
        
        -- Use a simple sequence that doesn't contain the sequence to be removed
        local result, changes, err = fix.cds("ATGTACTGA", ecoli_table, functions)
        
        -- Should return the original sequence unchanged
        assert.equals("ATGTACTGA", result)
        -- Should not be nil
        assert.is_not_nil(result)
        -- Should not have an error
        assert.is_nil(err)
        -- Changes should be empty
        assert.equals(0, #changes)
    end)
end)
